interface JudgeSchedulingContainerProps {
  eventId: string
  page: CrewJudgeRotationsPageData
  /** Currently selected workout ID (the wodsmith-start "event"). */
  selectedWorkoutId: string
  onWorkoutChange: (workoutId: string) => void
}

/**
 * Main container for Crew judge scheduling — a port of the wodsmith-start
 * organizer judging experience. Pre-publish, organizers plan judge coverage on
 * the Gantt-style Rotation Timeline; once a schedule is published the heat-lane
 * Published Assignments grid appears for per-lane fine-tuning. Rotations are
 * stored per judge and persisted through Crew's canonical-id-aware save path;
 * publishing materializes them through Crew's existing publish path.
 */
export function JudgeSchedulingContainer({
  eventId,
  page,
  selectedWorkoutId,
  onWorkoutChange,
}: JudgeSchedulingContainerProps) {
  const router = useRouter()
  const saveRotations = useServerFn(saveCrewJudgeRotationsForVolunteerFn)
  const publishRotations = useServerFn(publishCrewJudgeRotationsFn)

  const { workouts, heats, judges } = page

  const [availableJudgeSearch, setAvailableJudgeSearch] = useState("")
  const [selectedJudgeIds, setSelectedJudgeIds] = useState<Set<string>>(
    new Set(),
  )
  const [pendingJudgeIds, setPendingJudgeIds] = useState<Set<string>>(new Set())
  const [filterEmptyLanes, setFilterEmptyLanes] = useState(false)

  // Heats for the selected workout, sorted by heat number.
  const workoutHeats = useMemo(
    () =>
      heats
        .filter((h) => h.trackWorkoutId === selectedWorkoutId)
        .sort((a, b) => a.heatNumber - b.heatNumber),
    [heats, selectedWorkoutId],
  )

  // Max lanes across this workout's heats (fallback 10).
  const maxLanes = useMemo(() => {
    const max = workoutHeats.reduce(
      (acc, heat) => Math.max(acc, heat.laneCount),
      0,
    )
    return max > 0 ? max : 10
  }, [workoutHeats])

  // Saved rotations for the selected workout.
  const workoutRotations = useMemo(
    () =>
      page.rotations.filter(
        (rotation) => rotation.trackWorkoutId === selectedWorkoutId,
      ),
    [page.rotations, selectedWorkoutId],
  )

  // Saved rotations expanded into grid cells (for the heat-lane grid).
  const savedGridCells = useMemo(
    () => rotationsToGridCells(workoutRotations, workoutHeats),
    [workoutRotations, workoutHeats],
  )

  // Local, editable grid state for the heat-lane grid.
  const [gridCells, setGridCells] = useState<JudgeGridCell[]>(savedGridCells)
  useEffect(() => {
    setGridCells(savedGridCells)
  }, [savedGridCells])

  const judgeByMembershipId = useMemo(
    () => new Map(judges.map((judge) => [judge.membershipId, judge])),
    [judges],
  )

  const cellsByHeatNumber = useMemo(() => {
    const map = new Map<number, JudgeGridCell[]>()
    for (const cell of gridCells) {
      const list = map.get(cell.heatNumber) ?? []
      list.push(cell)
      map.set(cell.heatNumber, list)
    }
    return map
  }, [gridCells])

  const assignedJudgeIds = useMemo(
    () => new Set(gridCells.map((cell) => cell.membershipId)),
    [gridCells],
  )

  const unassignedJudges = useMemo(
    () => judges.filter((j) => !assignedJudgeIds.has(j.membershipId)),
    [judges, assignedJudgeIds],
  )

  const judgesByAssignmentCount = useMemo(() => {
    const counts = new Map<string, number>()
    for (const judge of judges) counts.set(judge.membershipId, 0)
    for (const cell of gridCells) {
      counts.set(cell.membershipId, (counts.get(cell.membershipId) ?? 0) + 1)
    }
    return [...judges]
      .map((judge) => ({
        ...judge,
        assignmentCount: counts.get(judge.membershipId) ?? 0,
      }))
      .sort((a, b) => a.assignmentCount - b.assignmentCount)
  }, [judges, gridCells])

  const filteredJudgesByAssignmentCount = useMemo(() => {
    if (!availableJudgeSearch.trim()) return judgesByAssignmentCount
    const query = availableJudgeSearch.toLowerCase().trim()
    return judgesByAssignmentCount.filter((judge) =>
      getCrewJudgeName(judge).toLowerCase().includes(query),
    )
  }, [judgesByAssignmentCount, availableJudgeSearch])

  const selectedWorkout = workouts.find(
    (workout) => workout.id === selectedWorkoutId,
  )
  const activeVersion = selectedWorkoutId
    ? page.activeVersionByWorkout[selectedWorkoutId]
    : null

  // Event-level rotation defaults (with sensible fallbacks).
  const eventLaneShiftPattern =
    selectedWorkout?.defaultLaneShiftPattern ?? LANE_SHIFT_PATTERN.STAY
  const eventDefaultHeatsCount =
    selectedWorkout?.defaultHeatsCount ?? Math.min(4, workoutHeats.length || 1)
  const minHeatBuffer = selectedWorkout?.minHeatBuffer ?? 2

  // Next version number for publish messaging.
  const nextVersionNumber = useMemo(() => {
    const history = page.versionHistoryByWorkout[selectedWorkoutId] ?? []
    return (history[0]?.version ?? 0) + 1
  }, [page.versionHistoryByWorkout, selectedWorkoutId])

  // Rotation coverage for the selected workout (drives the overview + publish).
  const rotationCoverage = useMemo(() => {
    if (workoutHeats.length === 0) {
      return {
        totalSlots: 0,
        coveredSlots: 0,
        coveragePercent: 0,
        gaps: [],
        overlaps: [],
      }
    }
    const heatsData = workoutHeats.map((heat) =>
      filterEmptyLanes
        ? {
            heatNumber: heat.heatNumber,
            laneCount: heat.laneCount,
            occupiedLanes: new Set(heat.occupiedLanes),
          }
        : { heatNumber: heat.heatNumber, laneCount: heat.laneCount },
    )
    return calculateCoverage(workoutRotations, heatsData)
  }, [workoutRotations, workoutHeats, filterEmptyLanes])

  // "Active judge" click-to-assign mode for the heat-lane grid.
  const activeJudgeId =
    selectedJudgeIds.size === 1 ? Array.from(selectedJudgeIds)[0] : null
  const activeJudge = activeJudgeId
    ? (judgeByMembershipId.get(activeJudgeId) ?? null)
    : null

  function markJudgePending(membershipId: string, pending: boolean) {
    setPendingJudgeIds((prev) => {
      const next = new Set(prev)
      if (pending) next.add(membershipId)
      else next.delete(membershipId)
      return next
    })
  }

  /**
   * Persist a set of judges' grid cells from a single already-computed `next`
   * cell set (heat-lane grid path). Optimistic; reverts on error.
   */
  async function persistJudges(
    membershipIds: string[],
    nextCells: JudgeGridCell[],
  ) {
    const uniqueIds = Array.from(new Set(membershipIds))
    if (uniqueIds.length === 0) return
    const previousCells = gridCells
    setGridCells(nextCells)
    for (const id of uniqueIds) markJudgePending(id, true)
    try {
      await Promise.all(
        uniqueIds.map((membershipId) =>
          saveRotations({
            data: {
              eventId,
              trackWorkoutId: selectedWorkoutId,
              membershipId,
              laneShiftPattern: JUDGE_GRID_LANE_SHIFT_PATTERN,
              rotations: gridCellsToRotationRows(
                nextCells.filter((cell) => cell.membershipId === membershipId),
              ),
            },
          }),
        ),
      )
      await router.invalidate()
    } catch (error) {
      setGridCells(previousCells)
      toast.error(
        error instanceof Error ? error.message : "Failed to save judges",
      )
    } finally {
      for (const id of uniqueIds) markJudgePending(id, false)
    }
  }

  function handleAssign(
    heatNumber: number,
    membershipId: string,
    laneNumber: number,
  ) {
    const next = gridCells.filter(
      (cell) =>
        !(
          (cell.membershipId === membershipId &&
            cell.heatNumber === heatNumber) ||
          (cell.heatNumber === heatNumber && cell.laneNumber === laneNumber)
        ),
    )
    const displaced = gridCells.filter(
      (cell) =>
        cell.heatNumber === heatNumber &&
        cell.laneNumber === laneNumber &&
        cell.membershipId !== membershipId,
    )
    next.push({ membershipId, heatNumber, laneNumber })
    void persistJudges(
      [membershipId, ...displaced.map((cell) => cell.membershipId)],
      next,
    )
  }

  function handleBulkAssign(
    heatNumber: number,
    placements: Array<{ membershipId: string; laneNumber: number }>,
  ) {
    let next = gridCells.slice()
    const touched: string[] = []
    for (const placement of placements) {
      next = next.filter(
        (cell) =>
          !(
            (cell.membershipId === placement.membershipId &&
              cell.heatNumber === heatNumber) ||
            (cell.heatNumber === heatNumber &&
              cell.laneNumber === placement.laneNumber)
          ),
      )
      next.push({
        membershipId: placement.membershipId,
        heatNumber,
        laneNumber: placement.laneNumber,
      })
      touched.push(placement.membershipId)
    }
    void persistJudges(touched, next)
  }

  function handleRemove(heatNumber: number, membershipId: string) {
    const next = gridCells.filter(
      (cell) =>
        !(cell.membershipId === membershipId && cell.heatNumber === heatNumber),
    )
    void persistJudges([membershipId], next)
  }

  function handleMove(
    membershipId: string,
    sourceHeatNumber: number,
    targetHeatNumber: number,
    targetLane: number,
  ) {
    const displaced = gridCells.filter(
      (cell) =>
        cell.heatNumber === targetHeatNumber &&
        cell.laneNumber === targetLane &&
        cell.membershipId !== membershipId,
    )
    const next = gridCells.filter(
      (cell) =>
        !(
          (cell.membershipId === membershipId &&
            (cell.heatNumber === sourceHeatNumber ||
              cell.heatNumber === targetHeatNumber)) ||
          (cell.heatNumber === targetHeatNumber &&
            cell.laneNumber === targetLane)
        ),
    )
    next.push({
      membershipId,
      heatNumber: targetHeatNumber,
      laneNumber: targetLane,
    })
    void persistJudges(
      [membershipId, ...displaced.map((cell) => cell.membershipId)],
      next,
    )
  }

  function handleLaneClick(heatNumber: number, laneNumber: number) {
    if (!activeJudgeId) return
    const occupant = gridCells.find(
      (cell) => cell.heatNumber === heatNumber && cell.laneNumber === laneNumber,
    )
    if (occupant?.membershipId === activeJudgeId) {
      handleRemove(heatNumber, activeJudgeId)
      return
    }
    handleAssign(heatNumber, activeJudgeId, laneNumber)
  }

  function handleAssignActiveJudgeToColumn(laneNumber: number) {
    if (!activeJudgeId) return
    const next = gridCells.filter(
      (cell) =>
        !(cell.membershipId === activeJudgeId || cell.laneNumber === laneNumber),
    )
    const displaced = gridCells.filter(
      (cell) =>
        cell.laneNumber === laneNumber && cell.membershipId !== activeJudgeId,
    )
    for (const heat of workoutHeats) {
      if (laneNumber <= heat.laneCount) {
        next.push({
          membershipId: activeJudgeId,
          heatNumber: heat.heatNumber,
          laneNumber,
        })
      }
    }
    void persistJudges(
      [activeJudgeId, ...displaced.map((cell) => cell.membershipId)],
      next,
    )
  }

  function handleFillHeat(heatNumber: number) {
    const heat = workoutHeats.find((h) => h.heatNumber === heatNumber)
    if (!heat) return
    const result = fillHeatWithAvailableJudges({
      cells: gridCells,
      heat,
      judgeOrder: judgesByAssignmentCount.map((judge) => judge.membershipId),
    })
    if (result.touched.length === 0) {
      toast.info("No open lanes or no available judges for this heat")
      return
    }
    void persistJudges(result.touched, result.cells)
  }

  function handleAutoFillWorkout() {
    const result = autoFillWorkout({
      cells: gridCells,
      heats: workoutHeats,
      judgeOrder: judgesByAssignmentCount.map((judge) => judge.membershipId),
    })
    if (result.touched.length === 0) {
      toast.info("Grid is already full or there are no judges to seat")
      return
    }
    void persistJudges(result.touched, result.cells)
  }

  function handleToggleSelect(membershipId: string, shiftKey: boolean) {
    setSelectedJudgeIds((prev) => {
      const next = new Set(prev)
      if (shiftKey && prev.size > 0) {
        const sortedJudges = judgesByAssignmentCount
        const lastSelected = Array.from(prev).pop()
        const lastIndex = sortedJudges.findIndex(
          (j) => j.membershipId === lastSelected,
        )
        const currentIndex = sortedJudges.findIndex(
          (j) => j.membershipId === membershipId,
        )
        if (lastIndex !== -1 && currentIndex !== -1) {
          const start = Math.min(lastIndex, currentIndex)
          const end = Math.max(lastIndex, currentIndex)
          for (let i = start; i <= end; i++) {
            const judge = sortedJudges[i]
            if (judge) next.add(judge.membershipId)
          }
          return next
        }
      }
      if (next.has(membershipId)) next.delete(membershipId)
      else next.add(membershipId)
      return next
    })
  }

  function clearSelection() {
    setSelectedJudgeIds(new Set())
  }

  /** Replace a single judge's rotations for the workout (Rotation Timeline). */
  async function handleSaveVolunteerRotations(
    membershipId: string,
    rotations: RotationDraft[],
  ) {
    await saveRotations({
      data: {
        eventId,
        trackWorkoutId: selectedWorkoutId,
        membershipId,
        laneShiftPattern: eventLaneShiftPattern,
        rotations,
      },
    })
    await router.invalidate()
  }

  /** Remove all of a judge's rotations for the workout (Rotation Timeline). */
  async function handleDeleteVolunteerRotations(membershipId: string) {
    await saveRotations({
      data: {
        eventId,
        trackWorkoutId: selectedWorkoutId,
        membershipId,
        laneShiftPattern: eventLaneShiftPattern,
        rotations: [],
      },
    })
    await router.invalidate()
  }

  /** Publish the draft rotations as a new active version. */
  async function handlePublish(notes: string) {
    if (!selectedWorkoutId) return
    try {
      const result = await publishRotations({
        data: {
          eventId,
          trackWorkoutId: selectedWorkoutId,
          notes: notes || undefined,
        },
      })
      toast.success(`Version ${result.version.version} published`)
      await router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error
          ? error.message
          : "Failed to publish judge schedule",
      )
      throw error
    }
  }

  function heatAssignments(heatNumber: number): HeatLaneAssignment[] {
    const cells = cellsByHeatNumber.get(heatNumber) ?? []
    return cells
      .map((cell) => {
        const volunteer = judgeByMembershipId.get(cell.membershipId)
        if (!volunteer) return null
        return {
          membershipId: cell.membershipId,
          laneNumber: cell.laneNumber,
          volunteer,
        }
      })
      .filter((value): value is HeatLaneAssignment => value !== null)
  }

  const isAnyPending = pendingJudgeIds.size > 0

  return (
    <section className="space-y-8">
      {/* Header + workout selector */}
      <div className="space-y-4">
        <div>
          <h2 className="text-xl font-semibold">Judging Schedule</h2>
          <p className="text-sm text-muted-foreground">
            Plan judge coverage on the rotation timeline, then publish. Once
            published, fine-tune individual lane assignments below.
          </p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <label htmlFor="event-selector" className="text-sm font-medium">
            Workout:
          </label>
          <Select value={selectedWorkoutId} onValueChange={onWorkoutChange}>
            <SelectTrigger id="event-selector" className="w-80">
              <SelectValue placeholder="Select workout" />
            </SelectTrigger>
            <SelectContent>
              {workouts.map((workout) => (
                <SelectItem key={workout.id} value={workout.id}>
                  Event {workout.trackOrder}: {workout.workout.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <span className="text-sm text-muted-foreground">
            {activeVersion
              ? `Published v${activeVersion.version}`
              : "Not published"}
          </span>
        </div>
      </div>

      {/* Published Assignments: per-lane heat grid, shown after publishing */}
      {selectedWorkout && workoutHeats.length > 0 && activeVersion && (
        <section className="space-y-6">
          <div>
            <h3 className="text-lg font-semibold">Published Assignments</h3>
            <p className="text-sm text-muted-foreground">
              Drag judges onto lanes, or pick a judge and click lanes to
              fine-tune the published schedule. Re-publish to lock in changes.
            </p>
          </div>

          {/* Active-judge hint */}
          {activeJudge ? (
            <div className="flex items-center gap-2 rounded-md border border-primary/40 bg-primary/5 px-3 py-2 text-sm">
              <MousePointerClick className="h-4 w-4 text-primary" />
              <span>
                Click any lane to seat{" "}
                <span className="font-medium">
                  {getCrewJudgeName(activeJudge)}
                </span>
                . Use a lane's column button to seat them down that lane for the
                whole workout.
              </span>
              <button
                type="button"
                onClick={clearSelection}
                className="ml-auto text-xs text-muted-foreground hover:text-foreground"
              >
                Done
              </button>
            </div>
          ) : null}

          <div className="flex flex-wrap items-center gap-3">
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={handleAutoFillWorkout}
              disabled={isAnyPending || unassignedJudges.length === 0}
            >
              <Sparkles className="mr-2 h-4 w-4" />
              Auto-fill workout
            </Button>
            {isAnyPending ? (
              <span className="flex items-center gap-1 text-xs text-muted-foreground">
                <Loader2 className="h-3 w-3 animate-spin" />
                Saving
              </span>
            ) : null}
          </div>

          <JudgeOverview workouts={workouts} heats={heats} gridCells={gridCells} />

          <div className="grid grid-cols-1 gap-6 lg:grid-cols-[280px_1fr]">
            {/* Available Judges Panel */}
            <Card className="lg:sticky lg:top-4 lg:self-start">
              <CardContent className="p-4">
                <div className="mb-3 flex items-center justify-between">
                  <h4 className="text-sm font-medium">Available Judges</h4>
                  {selectedJudgeIds.size > 0 && (
                    <button
                      type="button"
                      onClick={clearSelection}
                      className="text-xs text-muted-foreground hover:text-foreground"
                    >
                      Clear ({selectedJudgeIds.size})
                    </button>
                  )}
                </div>
                {judges.length === 0 ? (
                  <p className="py-4 text-center text-sm text-muted-foreground">
                    No judges have been added yet. Add volunteers with the Judge
                    role type in the Roster section.
                  </p>
                ) : (
                  <>
                    <p className="mb-3 text-xs text-muted-foreground">
                      Click a judge to enter click-to-assign mode, or drag them
                      onto a lane. Shift-click to multi-select for bulk drags.
                    </p>
                    <div className="relative mb-3">
                      <Search className="pointer-events-none absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                      <Input
                        type="text"
                        placeholder="Search judges..."
                        value={availableJudgeSearch}
                        onChange={(e) => setAvailableJudgeSearch(e.target.value)}
                        className="h-8 pl-8 text-sm"
                      />
                    </div>
                    <div className="max-h-[55vh] space-y-1.5 overflow-y-auto">
                      {filteredJudgesByAssignmentCount.map((judge) => (
                        <DraggableJudge
                          key={judge.membershipId}
                          volunteer={judge}
                          isSelected={selectedJudgeIds.has(judge.membershipId)}
                          onToggleSelect={handleToggleSelect}
                          selectedIds={selectedJudgeIds}
                          assignmentCount={judge.assignmentCount}
                          isAssignedToCurrentEvent={assignedJudgeIds.has(
                            judge.membershipId,
                          )}
                        />
                      ))}
                      {filteredJudgesByAssignmentCount.length === 0 &&
                        availableJudgeSearch && (
                          <p className="py-4 text-center text-sm text-muted-foreground">
                            No judges match "{availableJudgeSearch}"
                          </p>
                        )}
                    </div>
                  </>
                )}
              </CardContent>
            </Card>

            {/* Heats Grid */}
            <div className="space-y-4">
              {workoutHeats.map((heat) => (
                <JudgeHeatCard
                  key={heat.id}
                  heat={heat}
                  unassignedVolunteers={unassignedJudges}
                  assignments={heatAssignments(heat.heatNumber)}
                  maxLanes={maxLanes}
                  activeJudgeId={activeJudgeId}
                  onAssign={(membershipId, laneNumber) =>
                    handleAssign(heat.heatNumber, membershipId, laneNumber)
                  }
                  onBulkAssign={(placements) =>
                    handleBulkAssign(heat.heatNumber, placements)
                  }
                  onRemove={(membershipId) =>
                    handleRemove(heat.heatNumber, membershipId)
                  }
                  onMove={(membershipId, sourceHeatId, targetLane) => {
                    const sourceHeat = workoutHeats.find(
                      (h) => h.id === sourceHeatId,
                    )
                    handleMove(
                      membershipId,
                      sourceHeat?.heatNumber ?? heat.heatNumber,
                      heat.heatNumber,
                      targetLane,
                    )
                  }}
                  onLaneClick={(laneNumber) =>
                    handleLaneClick(heat.heatNumber, laneNumber)
                  }
                  onAssignActiveToColumn={handleAssignActiveJudgeToColumn}
                  onFillHeat={() => handleFillHeat(heat.heatNumber)}
                  isPending={isAnyPending}
                  selectedJudgeIds={selectedJudgeIds}
                  onClearSelection={clearSelection}
                />
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Rotations: coverage + publish, then the Gantt timeline (planning) */}
      {!selectedWorkout ? (
        <EmptyHeats message="Select a workout to schedule judges." />
      ) : workoutHeats.length === 0 ? (
        <EmptyHeats message="Create the heat schedule before assigning judges to lanes." />
      ) : (
        <section className="space-y-6">
          <div className="flex flex-wrap items-start justify-between gap-3">
            <div>
              <h3 className="text-lg font-semibold">Rotations</h3>
              <p className="text-sm text-muted-foreground">
                Click a grid cell or "Add" to plan a judge's rotation across
                heats, then publish.
              </p>
            </div>
            <Sheet>
              <SheetTrigger asChild>
                <Button variant="outline" size="sm">
                  <Settings2 className="mr-2 h-4 w-4" />
                  Event defaults
                </Button>
              </SheetTrigger>
              <SheetContent className="w-full overflow-y-auto sm:max-w-md">
                <SheetHeader>
                  <SheetTitle>Event defaults</SheetTitle>
                  <SheetDescription>
                    Defaults for new rotations on this workout — rotation length,
                    whether judges stay in lane or shift right each heat, and the
                    minimum heat buffer between a judge's rotations.
                  </SheetDescription>
                </SheetHeader>
                <div className="mt-4">
                  <EventDefaultsEditor
                    eventId={eventId}
                    trackWorkoutId={selectedWorkoutId}
                    defaultHeatsCount={selectedWorkout.defaultHeatsCount}
                    defaultLaneShiftPattern={
                      selectedWorkout.defaultLaneShiftPattern
                    }
                    minHeatBuffer={selectedWorkout.minHeatBuffer}
                  />
                </div>
              </SheetContent>
            </Sheet>
          </div>

          <RotationOverview
            rotations={workoutRotations}
            coverage={rotationCoverage}
            eventName={selectedWorkout.workout.name}
            hasActiveVersion={!!activeVersion}
            nextVersionNumber={nextVersionNumber}
            onPublish={handlePublish}
          />

          <RotationTimeline
            key={selectedWorkoutId}
            eventName={selectedWorkout.workout.name}
            heats={workoutHeats}
            laneCount={maxLanes}
            availableJudges={judges}
            initialRotations={workoutRotations}
            eventLaneShiftPattern={eventLaneShiftPattern}
            eventDefaultHeatsCount={eventDefaultHeatsCount}
            minHeatBuffer={minHeatBuffer}
            filterEmptyLanes={filterEmptyLanes}
            onFilterEmptyLanesChange={setFilterEmptyLanes}
            onSaveVolunteerRotations={handleSaveVolunteerRotations}
            onDeleteVolunteerRotations={handleDeleteVolunteerRotations}
          />
        </section>
      )}
    </section>
  )
}

function EmptyHeats({ message }: { message: string }) {
  return (
    <div className="rounded-md border bg-card p-8 text-center shadow-sm">
      <CalendarDays className="mx-auto mb-3 h-8 w-8 text-muted-foreground" />
      <p className="text-sm text-muted-foreground">{message}</p>
    </div>
  )
}

// @lat: [[crew#Judge Rotations]]
// @lat: [[crew#Server Function Runtime Boundary]]
import { createServerFn } from "@tanstack/react-start"
import { z } from "zod"
import { LANE_SHIFT_PATTERN } from "@/db/schemas/volunteers"

export type {
  CrewJudgeAssignmentVersion,
  CrewJudgeEvent,
  CrewJudgeHeat,
  CrewJudgeHeatAssignment,
  CrewJudgeRotationsPageData,
  CrewJudgeVolunteer,
  CrewJudgeWorkout,
} from "../server/crew-judge-rotations.server"

const eventIdSchema = z.string().min(1, "Event ID is required")
const trackWorkoutIdSchema = z.string().min(1, "Workout ID is required")
// The grid keys judges by a canonical assignee id: a membership id (tmem_) for
// account-backed volunteers, or an invitation id (tinv_) for imported / manual
// volunteers without an account.
const assigneeIdSchema = z
  .string()
  .refine(
    (value) => value.startsWith("tmem_") || value.startsWith("tinv_"),
    "Invalid judge assignee ID",
  )
const laneShiftPatternSchema = z.enum([
  LANE_SHIFT_PATTERN.STAY,
  LANE_SHIFT_PATTERN.SHIFT_RIGHT,
])
const optionalNotesSchema = z.string().trim().max(1000).nullable().optional()

const getCrewJudgeRotationsPageInputSchema = z.object({
  eventId: eventIdSchema,
})

const saveCrewJudgeRotationsForVolunteerInputSchema = z.object({
  eventId: eventIdSchema,
  trackWorkoutId: trackWorkoutIdSchema,
  membershipId: assigneeIdSchema,
  laneShiftPattern: laneShiftPatternSchema,
  rotations: z
    .array(
      z.object({
        startingHeat: z.number().int().min(1),
        startingLane: z.number().int().min(1),
        heatsCount: z.number().int().min(1),
        notes: optionalNotesSchema,
      }),
    )
    .max(50),
})

const publishCrewJudgeRotationsInputSchema = z.object({
  eventId: eventIdSchema,
  trackWorkoutId: trackWorkoutIdSchema,
  notes: optionalNotesSchema,
})

const updateCrewJudgeEventDefaultsInputSchema = z.object({
  eventId: eventIdSchema,
  trackWorkoutId: trackWorkoutIdSchema,
  defaultHeatsCount: z.number().int().min(1).max(20).nullable().optional(),
  defaultLaneShiftPattern: laneShiftPatternSchema.nullable().optional(),
  minHeatBuffer: z.number().int().min(1).max(10).nullable().optional(),
})

export const getCrewJudgeRotationsPageFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) =>
    getCrewJudgeRotationsPageInputSchema.parse(data),
  )
  .handler(async ({ data }) => {
    const { getCrewJudgeRotationsPage } = await import(
      "../server/crew-judge-rotations.server"
    )
    return getCrewJudgeRotationsPage(data)
  })

export const saveCrewJudgeRotationsForVolunteerFn = createServerFn({
  method: "POST",
})
  .inputValidator((data: unknown) =>
    saveCrewJudgeRotationsForVolunteerInputSchema.parse(data),
  )
  .handler(async ({ data }) => {
    const { saveCrewJudgeRotationsForVolunteer } = await import(
      "../server/crew-judge-rotations.server"
    )
    return saveCrewJudgeRotationsForVolunteer(data)
  })

export const publishCrewJudgeRotationsFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) =>
    publishCrewJudgeRotationsInputSchema.parse(data),
  )
  .handler(async ({ data }) => {
    const { publishCrewJudgeRotations } = await import(
      "../server/crew-judge-rotations.server"
    )
    return publishCrewJudgeRotations(data)
  })

export const updateCrewJudgeEventDefaultsFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) =>
    updateCrewJudgeEventDefaultsInputSchema.parse(data),
  )
  .handler(async ({ data }) => {
    const { updateCrewJudgeEventDefaults } = await import(
      "../server/crew-judge-rotations.server"
    )
    return updateCrewJudgeEventDefaults(data)
  })

export const judgeHeatAssignmentsTable = mysqlTable(
  "judge_heat_assignments",
  {
    ...commonColumns,
    id: varchar({ length: 255 })
      .primaryKey()
      .$defaultFn(() => createHeatVolunteerId())
      .notNull(),
    // The heat this volunteer is assigned to
    heatId: varchar({ length: 255 }).notNull(),
    // The team membership (account-backed volunteer with a volunteer role).
    // Null when the assignee is an invitation-based (imported / manual)
    // volunteer without an account — see invitationId below.
    membershipId: varchar({ length: 255 }),
    // The team invitation (imported / manual volunteer) being assigned. Null
    // when the assignee is an account-backed membership. Exactly one of
    // membershipId / invitationId is set per assignment.
    invitationId: varchar({ length: 255 }),
    // Optional reference to the rotation that generated this assignment
    // (null for manually created assignments)
    // IMPORTANT: Keep this - it tracks which rotation generated an assignment
    rotationId: varchar({ length: 255 }),
    // Optional reference to the version this assignment belongs to
    // (nullable for migration - assignments created before versioning)
    versionId: varchar({ length: 255 }),
    // Optional lane assignment (for lane judges)
    laneNumber: int(),
    // Position/role for this specific heat (overrides default from metadata)
    position: varchar({ length: 50 }).$type<VolunteerRoleType>(),
    // Heat-specific instructions for this volunteer
    instructions: text(),
    // Whether this assignment was manually overridden (not from rotation/version)
    isManualOverride: boolean().notNull().default(false),
  },
  (table) => [
    index("judge_heat_assignments_heat_idx").on(table.heatId),
    index("judge_heat_assignments_membership_idx").on(table.membershipId),
    index("judge_heat_assignments_invitation_idx").on(table.invitationId),
    index("judge_heat_assignments_rotation_idx").on(table.rotationId),
    index("judge_heat_assignments_version_idx").on(table.versionId),
    // Ensure a membership volunteer can only be assigned once per heat per
    // version. Invitation-based judges have a NULL membershipId, which MySQL
    // treats as distinct, so they are constrained by the invitation index below.
    uniqueIndex("judge_heat_assignments_unique_idx").on(
      table.heatId,
      table.membershipId,
      table.versionId,
    ),
    // Ensure an invitation volunteer can only be assigned once per heat per
    // version.
    uniqueIndex("judge_heat_assignments_invitation_unique_idx").on(
      table.heatId,
      table.invitationId,
      table.versionId,
    ),
  ],
)

