        rotations: [
          {
            membershipId: "tmem_judge_1",
            startingHeat: 1,
            startingLane: 2,
            heatsCount: 3,
            laneShiftPattern: LANE_SHIFT_PATTERN.SHIFT_RIGHT,
          },
        ],
      }),
